import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as o,o as t,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Começo Rápido","description":"","frontmatter":{},"headers":[],"relativePath":"pt/getting-started/quickstart.md","filePath":"pt/getting-started/quickstart.md"}'),s={name:"pt/getting-started/quickstart.md"};function d(n,a,c,l,p,u){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="comeco-rapido" tabindex="-1"><i class="ph ph-target"></i> Começo Rápido <a class="header-anchor" href="#comeco-rapido" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; Começo Rápido&quot;">​</a></h1><p>O plugin WebAP é projetado com a abordagem <em>Plug-and-Play</em>. Não é necessário escrever código ou adicionar gerenciadores à sua cena de inicialização — o sistema inicializa-se automaticamente.</p><h2 id="_1-ative-o-plugin" tabindex="-1">1. Ative o Plugin <a class="header-anchor" href="#_1-ative-o-plugin" aria-label="Permalink to &quot;1. Ative o Plugin&quot;">​</a></h2><ol><li>Navegue até <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong>.</li><li>Ative a opção <strong>Enable Web Adaptive Performance</strong>.</li><li>Expanda a aba Scalers e habilite os módulos adicionais que melhor se adaptam às especificações do seu jogo (por exemplo, passo de física ou qualidade de sombras) (Consulte <a href="./../scalers/reference">Referência de Scalers</a> para detalhes).</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">Configurações Padrão</p><p>As configurações padrão são pré-configuradas para oferecer o desempenho ideal para a maioria dos projetos. Mantenha-as inalteradas.</p></div><h2 id="_2-configure-as-player-settings" tabindex="-1">2. Configure as Player Settings <a class="header-anchor" href="#_2-configure-as-player-settings" aria-label="Permalink to &quot;2. Configure as Player Settings&quot;">​</a></h2><p>Para que o Tracker do plugin possa distinguir matematicamente entre os atrasos do processador (CPU) e da placa de vídeo (GPU), ele precisa de acesso aos tempos exatos dos frames no hardware.</p><div class="warning custom-block"><p class="custom-block-title">Estatísticas de Tempo de Frame (Frame Timing Stats)</p><p>Navegue até <strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> e marque <strong>Frame Timing Stats</strong>. Sem essa configuração, a detecção de Gargalo (Bottleneck) falhará em operar.</p></div><h2 id="_3-configure-os-graficos" tabindex="-1">3. Configure os Gráficos <a class="header-anchor" href="#_3-configure-os-graficos" aria-label="Permalink to &quot;3. Configure os Gráficos&quot;">​</a></h2><p>Pare de criar predefinições de qualidade separadas (Baixa, Média, Alta) para dispositivos diferentes, o que força o jogador a selecioná-las manualmente.</p><div class="tip custom-block"><p class="custom-block-title">Maximize a Qualidade Gráfica</p><p>Configure o seu projeto para a qualidade máxima. Para BiRP, faça isso em <code>Project Settings -&gt; Quality</code> e para URP, dentro do seu <code>URP Asset</code>. Se o dispositivo do jogador carecer de Margem de Desempenho (Performance Headroom), o plugin reduzirá automaticamente a carga de forma suave durante a execução, utilizando apenas os Scalers que você habilitou.</p></div>',12)])])}const h=o(s,[["render",d]]);export{f as __pageData,h as default};
